/// <summary>
/// Boss 1/8 (GDD 12.3.1, a confirmar) — "Guardião do Ferro Enraizado".
///
/// Preparação/scaffolding apenas (sem moveset implementado): liga-se a
/// BossController (vida, BossHealthBarUI, EnemyMultiPartBoss). A mecânica
/// própria (fases, ataques especiais, janela de vulnerabilidade, VFX/Animator)
/// fica para uma tarefa futura — ver TODOs nos hooks abaixo.
///
/// Ideias a confirmar com o GDD (pelo nome): guardião feito de ferro/raízes,
/// possivelmente com partes blindadas (raízes) que precisam de ser destruídas
/// antes do núcleo de ferro ficar vulnerável (EnemyMultiPartBoss +
/// Condition_BossPartsDestroyed já suportam este padrão).
/// </summary>
public class Boss_GuardiaoDoFerroEnraizado : BossController
{
    protected override void Awake()
    {
        base.Awake();
        if (string.IsNullOrEmpty(bossId)) bossId = "guardiao_ferro_enraizado";
        if (string.IsNullOrEmpty(displayName)) displayName = "Guardião do Ferro Enraizado";
    }

    protected override void OnIntroStart()
    {
        // TODO (moveset): activar ataques iniciais / animação de despertar.
    }

    protected override void OnPhaseChanged(int defeatedParts, int aliveParts)
    {
        // TODO (moveset): trocar de fase quando uma "raiz"/parte blindada cai
        // (ex: destravar novos ataques, acelerar, etc).
    }

    protected override void OnAllPartsDefeated()
    {
        // TODO (moveset): núcleo de ferro fica totalmente vulnerável.
    }

    protected override void OnDefeated()
    {
        // TODO (moveset): sequência de derrota (drops, Action_SetBossDefeated
        // via NpcAction/UnityEvent, animação final).
    }
}
